const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'http://localhost:3000/callback';
const authEndpoint = 'https://accounts.google.com/o/oauth2/v2/auth';
const tokenEndpoint = 'https://www.googleapis.com/oauth2/v4/token';
const scope = 'profile email';
let accessToken;

function login() {
    const url = `${authEndpoint}?client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=${scope}`;
    window.location.assign(url);
}

async function exchangeCodeForToken(code) {
    const response = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: `client_id=${clientId}&client_secret=YOUR_CLIENT_SECRET&code=${code}&redirect_uri=${encodeURIComponent(redirectUri)}&grant_type=authorization_code`,
    });
    const { access_token } = await response.json();
    localStorage.setItem('accessToken', accessToken);
}

function handleCallback() {
    const params = new URLSearchParams(window.location.search);
    const code = params.get('code');
    if (code) {
        exchangeCodeForToken(code).then(() => window.history.replaceState({}, null, '/'));
    }
}

window.onload = function() {
    handleCallback();
};